// ============================================================
// WEEKLY METRICS - from "Airtable - Weekly Deals"
// ============================================================
const weeklyItems = $('Airtable - Weekly Deals').all();
const activeRepItems = $('Airtable - Active Reps').all();

// Reps excluidos del per-rep y rates, pero SI cuentan en volumen total
const EXCLUDED_REPS = ['Bradley Fry'];

// Build lookup: recordId -> Full Name, y recolectar TODOS los reps
const repIdToName = {};
const allRepNames = new Set();
for (const item of activeRepItems) {
  const row = item.json.fields ?? item.json;
  const fullName = String(row['Full Name'] ?? '').trim();
  const recordId = item.json.id ?? '';
  if (fullName) {
    allRepNames.add(fullName);
    if (recordId) repIdToName[recordId] = fullName;
  }
}

// activeRepNames = los que SI van a per-rep / rates (sin Bradley)
const activeRepNames = new Set([...allRepNames].filter(n => !EXCLUDED_REPS.includes(n)));

const CONFIG = {
  createdField: 'Date Created',
  minutesField: 'Lead to Quote (Minutes) During Business Hours',
  repField: 'Sales',
  stageField: 'Stage',
  stageQuote: 'Quote',
};

function resolveRep(value) {
  if (Array.isArray(value)) {
    return value.map(v => resolveRep(v)).flat().filter(Boolean);
  }
  let str = String(value ?? '').trim();
  if (!str) return [];
  str = str.replace(/^\d+:/, '');
  if (str.startsWith('rec') && repIdToName[str]) {
    return [repIdToName[str]];
  }
  if (allRepNames.has(str)) {
    return [str];
  }
  if (!str.startsWith('rec')) {
    return [str];
  }
  return [];
}

function normalizeStage(value) {
  if (Array.isArray(value)) return String(value[0] ?? '').trim();
  return String(value ?? '').trim();
}

function toNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  if (Array.isArray(value)) {
    if (value.length === 0) return null;
    value = value[0];
  }
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function getStartOfWeekMonday(date) {
  const d = new Date(date);
  const day = d.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + diff);
  return d;
}

function getEndOfWeekSunday(date) {
  const start = getStartOfWeekMonday(date);
  const end = new Date(start);
  end.setDate(end.getDate() + 6);
  end.setHours(23, 59, 59, 999);
  return end;
}

function isWithinRange(dateValue, start, end) {
  if (!dateValue) return false;
  const d = new Date(dateValue);
  if (Number.isNaN(d.getTime())) return false;
  return d >= start && d <= end;
}

function formatDateKey(dateValue) {
  const d = new Date(dateValue);
  if (Number.isNaN(d.getTime())) return '';
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

function formatHours(minutes) {
  if (minutes === null || minutes === undefined || !Number.isFinite(minutes)) return '';
  const totalMinutes = Math.round(minutes);
  const days = Math.floor(totalMinutes / 1440);
  const hours = Math.floor((totalMinutes % 1440) / 60);
  const mins = totalMinutes % 60;
  const parts = [];
  if (days) parts.push(`${days}d`);
  if (hours || days) parts.push(`${hours}h`);
  parts.push(`${mins}m`);
  return parts.join(' ');
}

const now = new Date();
const weekStart = getStartOfWeekMonday(now);
const weekEnd = getEndOfWeekSunday(now);

// reps de display (sin Bradley)
const reps = Array.from(activeRepNames).sort((a, b) => a.localeCompare(b));
const weeklyRecords = [];

for (const item of weeklyItems) {
  const row = item.json.fields ?? item.json;
  const created = row[CONFIG.createdField];
  const minutes = toNumber(row[CONFIG.minutesField]);
  const resolvedReps = resolveRep(row[CONFIG.repField]);
  const rep = resolvedReps[0] ?? '';
  const stage = normalizeStage(row[CONFIG.stageField]);
  const lmtQuoteStage = row['LMT - Quote Stage (For Follow Up)'];

  if (isWithinRange(created, weekStart, weekEnd)) {
    weeklyRecords.push({
      created,
      createdDateKey: formatDateKey(created),
      minutes,
      rep,
      stage,
      lmtQuoteStage,
    });
  }
}

// --- Weekly Summary ---
const summary = {
  Week_Start: formatDateKey(weekStart),
  Week_End: formatDateKey(weekEnd),
  'Total_Leads (with Bradley)': 0,
  'Total_Leads (Active Reps)': 0,
  'Total_Quotes (with Bradley)': 0,
  'Total_Quotes (Active Reps)': 0,
  Avg_Response_Min: 0,
  Avg_Response_Time: '0m',
  Active_Reps: reps.length,
  Last_Refresh: new Date().toISOString(),
};


// Counters para rates (sin Bradley)
let activeLeadsCount = 0;
let activeQuotesCount = 0;

// --- Weekly By Rep (solo reps activos) ---
const byRep = {};
const dailyQuotesMap = {};

for (const rep of reps) {
  byRep[rep] = {
    Rep: rep,
    Leads: 0,
    Quotes: 0,
    total_quote_minutes: 0,
    quote_time_count: 0,
    Avg_Response_Min: '0 min',
    Avg_Response_Time: '0m',
  };
}

for (const row of weeklyRecords) {
  // Saltar registros con rep desconocido
  if (!row.rep || !allRepNames.has(row.rep)) continue;

  // VOLUMEN: cuenta a todos (incluye Bradley)
  summary['Total_Leads (with Bradley)'] += 1;
  if (row.lmtQuoteStage) {
    summary['Total_Quotes (with Bradley)'] += 1;
  }

  // Si el rep es excluido (Bradley), saltar per-rep + quality
  if (EXCLUDED_REPS.includes(row.rep)) continue;

  // PER-REP + RATES (solo reps activos)
  if (!dailyQuotesMap[row.rep]) dailyQuotesMap[row.rep] = {};
  if (!dailyQuotesMap[row.rep][row.createdDateKey]) dailyQuotesMap[row.rep][row.createdDateKey] = 0;

  byRep[row.rep].Leads += 1;
  activeLeadsCount += 1;

  if (row.lmtQuoteStage) {
    byRep[row.rep].Quotes += 1;
    activeQuotesCount += 1;
    dailyQuotesMap[row.rep][row.createdDateKey] += 1;
  }

  if (row.lmtQuoteStage && row.minutes !== null && row.minutes > 0) {
    byRep[row.rep].total_quote_minutes += row.minutes;
    byRep[row.rep].quote_time_count += 1;
    summary.Avg_Response_Min += row.minutes;
  }
}

let overallQuoteTimeCount = 0;
const byRepRows = Object.values(byRep).map((r) => {
  if (r.quote_time_count > 0) {
    const avgMin = Number((r.total_quote_minutes / r.quote_time_count).toFixed(2));
    r.Avg_Response_Time = formatHours(avgMin);
    r.Avg_Response_Min = `${avgMin.toFixed(2)} min`;
    overallQuoteTimeCount += r.quote_time_count;
  }
  delete r.total_quote_minutes;
  delete r.quote_time_count;
  return r;
});

let summaryAvgMin = 0;
if (overallQuoteTimeCount > 0) {
  summaryAvgMin = Number((summary.Avg_Response_Min / overallQuoteTimeCount).toFixed(2));
}
summary.Avg_Response_Time = formatHours(summaryAvgMin);
summary.Avg_Response_Min = `${summaryAvgMin.toFixed(2)} min`;



// Asignar el total de leads y quotes de reps activos
summary['Total_Leads (Active Reps)'] = activeLeadsCount;
summary['Total_Quotes (Active Reps)'] = activeQuotesCount;


// Quote_Rate_Pct = quotes activos / leads activos (sin Bradley)
summary.Quote_Rate_Pct = activeLeadsCount
  ? `${((activeQuotesCount / activeLeadsCount) * 100).toFixed(2)}%`
  : '0%';

// Avg_Quotes_Per_Rep solo cuenta reps activos
summary.Avg_Quotes_Per_Rep = reps.length
  ? Number((activeQuotesCount / reps.length).toFixed(2))
  : 0;

const rankedByQuotes = [...byRepRows].sort((a, b) => {
  if (b.Quotes !== a.Quotes) return b.Quotes - a.Quotes;
  return a.Rep.localeCompare(b.Rep);
});

summary.Top_Rep_By_Quotes = rankedByQuotes[0]?.Rep ?? '';
summary.Top_Rep_Quote_Count = rankedByQuotes[0]?.Quotes ?? 0;

const repsWithResponse = byRepRows
  .map(r => ({ ...r, _minNum: parseFloat(r.Avg_Response_Min) }))
  .filter(r => Number.isFinite(r._minNum) && r._minNum > 0)
  .sort((a, b) => {
    if (a._minNum !== b._minNum) return a._minNum - b._minNum;
    return a.Rep.localeCompare(b.Rep);
  });

summary.Fastest_Rep = repsWithResponse[0]?.Rep ?? '';
summary.Fastest_Rep_Avg_Min = repsWithResponse[0]?.Avg_Response_Min ?? '0 min';
summary.Fastest_Rep_Avg_Time = repsWithResponse[0]?.Avg_Response_Time ?? '';

// --- Daily Quotes (solo reps activos) ---
const dailyRows = [];
const dates = [];

const cursor = new Date(weekStart);
while (cursor <= weekEnd) {
  dates.push(formatDateKey(cursor));
  cursor.setDate(cursor.getDate() + 1);
}

for (const rep of reps) {
  const row = { Rep: rep };
  let total = 0;

  for (const d of dates) {
    const value = Number(dailyQuotesMap[rep]?.[d] ?? 0);
    row[d] = value;
    total += value;
  }

  row.Total = total;
  dailyRows.push(row);
}

return [
  { json: { sheet: 'Dashboard_Summary', data: [summary] } },
  { json: { sheet: 'Weekly_By_Rep', data: byRepRows } },
  { json: { sheet: 'Daily_Quotes', data: dailyRows } },
];

const allItems = $('Airtable - Monthly Deals').all();
const activeRepItems = $('Airtable - Active Reps').all();

// Reps excluidos del per-rep y rates, pero SI cuentan en volumen total
const EXCLUDED_REPS = ['Bradley Fry'];

const repIdToName = {};
const allRepNames = new Set();
for (const item of activeRepItems) {
  const row = item.json.fields ?? item.json;
  const fullName = String(row['Full Name'] ?? '').trim();
  const recordId = item.json.id ?? '';
  if (fullName) {
    allRepNames.add(fullName);
    if (recordId) repIdToName[recordId] = fullName;
  }
}

const activeRepNames = new Set([...allRepNames].filter(n => !EXCLUDED_REPS.includes(n)));

const CONFIG = {
  createdField: 'Date Created',
  repField: 'Sales',
  stageField: 'Stage',
  artworkField: 'LMT Art Sent To Customer (from Artwork)',
};

function resolveRep(value) {
  if (Array.isArray(value)) {
    return value.map(v => resolveRep(v)).flat().filter(Boolean);
  }
  let str = String(value ?? '').trim();
  if (!str) return [];
  str = str.replace(/^\d+:/, '');
  if (str.startsWith('rec') && repIdToName[str]) {
    return [repIdToName[str]];
  }
  if (allRepNames.has(str)) {
    return [str];
  }
  if (!str.startsWith('rec')) {
    return [str];
  }
  return [];
}

function normalizeStage(value) {
  if (Array.isArray(value)) return String(value[0] ?? '').trim();
  return String(value ?? '').trim();
}

function formatPct(num, den) {
  if (!den) return '0.00%';
  return `${((num / den) * 100).toFixed(2)}%`;
}

const now = new Date();
const monthLabel = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

const reps = Array.from(activeRepNames).sort((a, b) => a.localeCompare(b));
const byRep = {};

// Volumen total (INCLUYE Bradley)
let displayTotalLeads = 0;
let displayTotalArtwork = 0;
let displayTotalClosedWon = 0;

for (const item of allItems) {
  const row = item.json.fields ?? item.json;
  const resolvedReps = resolveRep(row[CONFIG.repField]);
  const rep = resolvedReps[0] ?? '';
  if (!rep || !allRepNames.has(rep)) continue;

  // Computar artwork y stage una sola vez
  const artworkValue = row[CONFIG.artworkField];
  const hasArtwork = Array.isArray(artworkValue)
    ? artworkValue.length > 0
    : (artworkValue !== null && artworkValue !== undefined && artworkValue !== '');
  const stage = normalizeStage(row[CONFIG.stageField]);
  const isClosedWon = stage === 'Closed Won';

  // VOLUMEN total (incluye Bradley)
  displayTotalLeads += 1;
  if (hasArtwork) displayTotalArtwork += 1;
  if (isClosedWon) displayTotalClosedWon += 1;

  // PER-REP + RATES: solo reps activos (sin Bradley)
  if (EXCLUDED_REPS.includes(rep)) continue;

  if (!byRep[rep]) {
    byRep[rep] = { total_leads: 0, artwork_reached: 0, closed_won: 0 };
  }
  byRep[rep].total_leads += 1;
  if (hasArtwork) byRep[rep].artwork_reached += 1;
  if (isClosedWon) byRep[rep].closed_won += 1;
}

const monthlyByRepRows = reps.map((rep) => {
  const d = byRep[rep] ?? { total_leads: 0, artwork_reached: 0, closed_won: 0 };
  return {
    Rep: rep,
    Month: monthLabel,
    Total_Leads: d.total_leads,
    Artwork_Sent: d.artwork_reached,
    Lead_to_Art_Pct: formatPct(d.artwork_reached, d.total_leads),
    Closed_Won: d.closed_won,
    Close_Rate_Pct: formatPct(d.closed_won, d.total_leads),
    Last_Refresh: new Date().toISOString(),
  };
});

// Subtotales solo de reps activos (para los rates del summary)
const activeTotalLeads = monthlyByRepRows.reduce((s, r) => s + r.Total_Leads, 0);
const activeTotalArtwork = monthlyByRepRows.reduce((s, r) => s + r.Artwork_Sent, 0);
const activeTotalClosedWon = monthlyByRepRows.reduce((s, r) => s + r.Closed_Won, 0);

const monthlySummary = {
  Month: monthLabel,
  'Total_Leads (with Bradley)': displayTotalLeads,                          // INCLUYE Bradley
  'Total_Leads (Active Reps)': activeTotalLeads,                            // SIN Bradley
  'Artwork_Sent (with Bradley)': displayTotalArtwork,                       // INCLUYE Bradley
  'Artwork_Sent (Active Reps)': activeTotalArtwork,                         // SIN Bradley
  Lead_to_Art_Pct: formatPct(activeTotalArtwork, activeTotalLeads),         // sin Bradley
  'Total_Closed_Won (with Bradley)': displayTotalClosedWon,                 // INCLUYE Bradley
  'Total_Closed_Won (Active Reps)': activeTotalClosedWon,                   // SIN Bradley
  Close_Rate_Pct: formatPct(activeTotalClosedWon, activeTotalLeads),        // sin Bradley
  Active_Reps: reps.length,
  Last_Refresh: new Date().toISOString(),
};

return [
  { json: { sheet: 'Monthly_Summary', data: [monthlySummary] } },
  { json: { sheet: 'Monthly_By_Rep', data: monthlyByRepRows } },
];

// Build Google Sheets batchUpdate formatting requests
const SHEET_GIDS = {
  "Hoja 1": 0,
  "Weekly_By_Rep": 1693801572,
  "Daily_Quotes": 973934632,
  "Monthly_Summary": 312312681,
  "Monthly_By_Rep": 1362992793,
};
function rgb(r, g, b) {
  return { red: r / 255, green: g / 255, blue: b / 255 };
}
// Color palette
const DARK_NAVY = rgb(26, 35, 55);
const MEDIUM_BLUE = rgb(55, 71, 103);
const ACCENT_BLUE = rgb(66, 133, 244);
const LIGHT_BG = rgb(245, 247, 250);
const WHITE = rgb(255, 255, 255);
const HEADER_TEXT = rgb(255, 255, 255);
const DARK_TEXT = rgb(33, 37, 41);
const SUBTLE_TEXT = rgb(108, 117, 125);
const SUCCESS_GREEN = rgb(40, 167, 69);
const SUCCESS_BG = rgb(232, 245, 233);
const WARNING_AMBER = rgb(255, 152, 0);
const WARNING_BG = rgb(255, 243, 224);
const BORDER_COLOR = rgb(218, 220, 224);
const ACCENT_TEAL = rgb(0, 150, 136);
const ACCENT_PURPLE = rgb(103, 58, 183);
const KPI_BG_1 = rgb(232, 240, 254);
const KPI_BG_2 = rgb(232, 245, 233);
const KPI_BG_3 = rgb(255, 243, 224);
const KPI_BG_4 = rgb(243, 229, 245);

// --- Dynamic row counts based on active reps ---
const EXCLUDED_REPS = ['Bradley Fry'];
const activeRepItems = $('Airtable - Active Reps').all().filter(item => {
  const row = item.json.fields ?? item.json;
  const fullName = String(row['Full Name'] ?? '').trim();
  return !EXCLUDED_REPS.includes(fullName);
});
const activeRepCount = activeRepItems.length;

// Header row is row 0, data starts at row 1
const dailyQuotesEndRow = activeRepCount + 1;
const weeklyByRepEndRow = activeRepCount + 1;
const monthlyByRepEndRow = activeRepCount + 1;

const requests = [];

// Helper: format a header row
function formatHeader(sheetId, row, endCol, bgColor) {
  requests.push({
    repeatCell: {
      range: { sheetId, startRowIndex: row, endRowIndex: row + 1, startColumnIndex: 0, endColumnIndex: endCol },
      cell: {
        userEnteredFormat: {
          backgroundColor: bgColor || DARK_NAVY,
          textFormat: { foregroundColor: HEADER_TEXT, bold: true, fontSize: 10, fontFamily: 'Inter' },
          horizontalAlignment: 'CENTER',
          verticalAlignment: 'MIDDLE',
          padding: { top: 6, bottom: 6, left: 8, right: 8 },
        }
      },
      fields: 'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,verticalAlignment,padding)'
    }
  });
}
// Helper: alternate row colors
function alternateRows(sheetId, startRow, endRow, endCol) {
  for (let r = startRow; r < endRow; r++) {
    const bg = (r - startRow) % 2 === 0 ? WHITE : LIGHT_BG;
    requests.push({
      repeatCell: {
        range: { sheetId, startRowIndex: r, endRowIndex: r + 1, startColumnIndex: 0, endColumnIndex: endCol },
        cell: {
          userEnteredFormat: {
            backgroundColor: bg,
            textFormat: { foregroundColor: DARK_TEXT, fontSize: 10, fontFamily: 'Inter' },
            verticalAlignment: 'MIDDLE',
            padding: { top: 4, bottom: 4, left: 8, right: 8 },
          }
        },
        fields: 'userEnteredFormat(backgroundColor,textFormat,verticalAlignment,padding)'
      }
    });
  }
}
// Helper: add borders to a range
function addBorders(sheetId, startRow, endRow, startCol, endCol) {
  requests.push({
    updateBorders: {
      range: { sheetId, startRowIndex: startRow, endRowIndex: endRow, startColumnIndex: startCol, endColumnIndex: endCol },
      top: { style: 'SOLID', width: 1, color: BORDER_COLOR },
      bottom: { style: 'SOLID', width: 1, color: BORDER_COLOR },
      left: { style: 'SOLID', width: 1, color: BORDER_COLOR },
      right: { style: 'SOLID', width: 1, color: BORDER_COLOR },
      innerHorizontal: { style: 'SOLID', width: 1, color: BORDER_COLOR },
      innerVertical: { style: 'SOLID', width: 1, color: BORDER_COLOR },
    }
  });
}
// Helper: set column widths
function setColWidth(sheetId, col, width) {
  requests.push({
    updateDimensionProperties: {
      range: { sheetId, dimension: 'COLUMNS', startIndex: col, endIndex: col + 1 },
      properties: { pixelSize: width },
      fields: 'pixelSize'
    }
  });
}
// Helper: set row height
function setRowHeight(sheetId, row, height) {
  requests.push({
    updateDimensionProperties: {
      range: { sheetId, dimension: 'ROWS', startIndex: row, endIndex: row + 1 },
      properties: { pixelSize: height },
      fields: 'pixelSize'
    }
  });
}
// Helper: freeze rows
function freezeRows(sheetId, numRows) {
  requests.push({
    updateSheetProperties: {
      properties: { sheetId, gridProperties: { frozenRowCount: numRows } },
      fields: 'gridProperties.frozenRowCount'
    }
  });
}

// ============================================================
// SHEET 1: "Hoja 1" - Dashboard Summary
// Orden esperado de columnas:
//   0: Week_Start
//   1: Week_End
//   2: Total_Leads (with Bradley)
//   3: Total_Leads (Active Reps)
//   4: Total_Quotes (with Bradley)
//   5: Total_Quotes (Active Reps)
//   6: Quote_Rate_Pct
//   7: Avg_Response_Min
//   8: Avg_Response_Time
//   9: Avg_Quotes_Per_Rep
//  10: Top_Rep_By_Quotes
//  11: Top_Rep_Quote_Count
//  12: Fastest_Rep
//  13: Fastest_Rep_Avg_Min
//  14: Fastest_Rep_Avg_Time
//  15: Active_Reps
//  16: Last_Refresh
// ============================================================
const s0 = SHEET_GIDS["Hoja 1"];
const HOJA1_COLS = 17;

[
  120, // 0  Week_Start
  120, // 1  Week_End
  180, // 2  Total_Leads (with Bradley)
  180, // 3  Total_Leads (Active Reps)
  190, // 4  Total_Quotes (with Bradley)
  190, // 5  Total_Quotes (Active Reps)
  130, // 6  Quote_Rate_Pct
  150, // 7  Avg_Response_Min
  150, // 8  Avg_Response_Time
  150, // 9  Avg_Quotes_Per_Rep
  180, // 10 Top_Rep_By_Quotes
  150, // 11 Top_Rep_Quote_Count
  180, // 12 Fastest_Rep
  150, // 13 Fastest_Rep_Avg_Min
  150, // 14 Fastest_Rep_Avg_Time
  110, // 15 Active_Reps
  220, // 16 Last_Refresh
].forEach((w, i) => setColWidth(s0, i, w));

// Header row
formatHeader(s0, 0, HOJA1_COLS);
setRowHeight(s0, 0, 40);
freezeRows(s0, 1);

// Data row styling
alternateRows(s0, 1, 2, HOJA1_COLS);
addBorders(s0, 0, 2, 0, HOJA1_COLS);

// Center align
requests.push({
  repeatCell: {
    range: { sheetId: s0, startRowIndex: 1, endRowIndex: 2, startColumnIndex: 0, endColumnIndex: HOJA1_COLS },
    cell: {
      userEnteredFormat: {
        horizontalAlignment: 'CENTER',
        verticalAlignment: 'MIDDLE'
      }
    },
    fields: 'userEnteredFormat(horizontalAlignment,verticalAlignment)'
  }
});

// Number format: Avg_Quotes_Per_Rep (col 9) - decimal
requests.push({
  repeatCell: {
    range: { sheetId: s0, startRowIndex: 1, endRowIndex: 2, startColumnIndex: 9, endColumnIndex: 10 },
    cell: { userEnteredFormat: { numberFormat: { type: 'NUMBER', pattern: '0.00' } } },
    fields: 'userEnteredFormat.numberFormat'
  }
});

// Integer format: Total_Leads x2, Total_Quotes x2, Top_Rep_Quote_Count, Active_Reps
[2, 3, 4, 5, 8, 11].forEach((col) => {
  requests.push({
    repeatCell: {
      range: { sheetId: s0, startRowIndex: 1, endRowIndex: 2, startColumnIndex: col, endColumnIndex: col + 1 },
      cell: { userEnteredFormat: { numberFormat: { type: 'NUMBER', pattern: '0' } } },
      fields: 'userEnteredFormat.numberFormat'
    }
  });
});


// ============================================================
// SHEET 2: Weekly_By_Rep
// 0: Rep | 1: Leads | 2: Quotes | 3: Avg_Response_Min | 4: Avg_Response_Time
// ============================================================
const s1 = SHEET_GIDS["Weekly_By_Rep"];

[180, 140, 140, 200, 200].forEach((w, i) => setColWidth(s1, i, w));
formatHeader(s1, 0, 5, ACCENT_TEAL);
setRowHeight(s1, 0, 36);
freezeRows(s1, 1);
alternateRows(s1, 1, weeklyByRepEndRow, 5);
addBorders(s1, 0, weeklyByRepEndRow, 0, 5);

// Bold the rep name column
requests.push({
  repeatCell: {
    range: { sheetId: s1, startRowIndex: 1, endRowIndex: weeklyByRepEndRow, startColumnIndex: 0, endColumnIndex: 1 },
    cell: { userEnteredFormat: { textFormat: { bold: true, foregroundColor: DARK_TEXT, fontSize: 10, fontFamily: 'Inter' } } },
    fields: 'userEnteredFormat.textFormat'
  }
});

// Integer format: Leads, Quotes
[1, 2].forEach((col) => {
  requests.push({
    repeatCell: {
      range: { sheetId: s1, startRowIndex: 1, endRowIndex: weeklyByRepEndRow, startColumnIndex: col, endColumnIndex: col + 1 },
      cell: { userEnteredFormat: { numberFormat: { type: 'NUMBER', pattern: '0' } } },
      fields: 'userEnteredFormat.numberFormat'
    }
  });
});

// ============================================================
// SHEET 3: Daily_Quotes (pivoted: Rep | Mon-Sun | Total)
