function getStartOfWeekMonday(date) {
  const d = new Date(date);
  const day = d.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + diff);
  return d;
}

function getEndOfWeekSunday(date) {
  const start = getStartOfWeekMonday(date);
  const end = new Date(start);
  end.setDate(end.getDate() + 6);
  end.setHours(23, 59, 59, 999);
  return end;
}

function formatDateYMD(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

const now = new Date();
const weekStart = getStartOfWeekMonday(now);
const weekEnd = getEndOfWeekSunday(now);

return {
  weekStartDate: formatDateYMD(weekStart),
  weekEndDate: formatDateYMD(weekEnd),
};

function getStartOfMonth(date) {
  const d = new Date(date);
  d.setDate(1);
  d.setHours(0, 0, 0, 0);
  return d;
}

function getEndOfMonth(date) {
  const d = new Date(date);
  // Día 0 del mes siguiente = último día del mes actual
  d.setMonth(d.getMonth() + 1, 0);
  d.setHours(23, 59, 59, 999);
  return d;
}

function formatDateYMD(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

const now = new Date();
const monthStart = getStartOfMonth(now);
const monthEnd = getEndOfMonth(now);

return {
  monthStartDate: formatDateYMD(monthStart),
  monthEndDate: formatDateYMD(monthEnd),
};
